import React from "react";
import { getImage } from "../../utils/getImage";

export default function Grid({
  items,
  selectedId,
  onSelect,
  hoveredId,
  setHovered,
  isSingle,
}) {
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: isSingle
          ? "repeat(auto-fit, minmax(260px, 1fr))"
          : "repeat(auto-fill, minmax(220px, 1fr))",
        gap: "14px",
      }}
    >
      {items.map((item) => {
        const isSelected = selectedId === item.id;

        return (
          <button
            key={item.id}
            onClick={() => onSelect(item)}
            onMouseEnter={() => setHovered(item.id)}
            onMouseLeave={() => setHovered(null)}
            style={{
              all: "unset",
              cursor: "pointer",
              display: "block",
            }}
          >
            {/* TARJETA */}
            <div
  style={{
    borderRadius: "12px",
    overflow: "hidden",
    background: "#fff",
    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
    transition: "transform 0.2s ease",
    transform: hoveredId === item.id ? "scale(1.02)" : "scale(1)",
  }}
>
  {/* IMAGEN */}
  <div
    style={{
      width: "100%",
      aspectRatio: "3 / 4",
      overflow: "hidden",
      background: "#eee",
    }}
  >
    <img
      src={getImage(item, "thumb")}
      alt={item.titulo}
      loading="lazy"
      style={{
        width: "100%",
        height: "100%",
        objectFit: "cover",
      }}
    />
  </div>

  {/* TEXTO */}
  <div style={{ padding: "8px 10px" }}>
    <div
      style={{
        fontSize: "13px",
        fontWeight: "600",
        color: "#333",
        lineHeight: 1.2,
      }}
    >
      {item.titulo}
    </div>

    {item.descripcion && (
      <div
        style={{
          fontSize: "11px",
          color: "#777",
          marginTop: "2px",
          overflow: "hidden",
          textOverflow: "ellipsis",
          whiteSpace: "nowrap",
        }}
      >
        {item.descripcion}
      </div>
    )}
  </div>
</div>
          </button>
        );
      })}
    </div>
  );
}
